import React, { useState } from "react";

const AnadirUsuario = () => {
  const [esCrearCuenta, setEsCrearCuenta] = useState(true);
  const [formulario, setFormulario] = useState({
    usuario: "",
    contrasena: "",
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormulario({
      ...formulario,
      [name]: value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Datos del usuario:", formulario);
    alert(`${esCrearCuenta ? "Cuenta creada" : "Inicio de sesión exitoso"}`);
  };

  return (
    <div className="flex justify-center items-center min-h-screen bg-gradient-to-r from-blue-500 to-purple-500 p-4">
      <div className="bg-white p-8 rounded-lg shadow-xl w-full max-w-md">
        <h2 className="text-3xl font-semibold text-center text-gray-800 mb-6">
          {esCrearCuenta ? "Crear Cuenta" : "Iniciar Sesión"}
        </h2>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Campo Usuario en ambos casos */}
          <div>
            <label className="block text-lg font-medium text-gray-700">Usuario</label>
            <input
              type="text"
              name="usuario"
              value={formulario.usuario}
              onChange={handleChange}
              className="w-full border border-gray-300 rounded-lg p-3 mt-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
              maxLength={50}
              required
            />
          </div>

          {/* Campo Contraseña */}
          <div>
            <label className="block text-lg font-medium text-gray-700">Contraseña</label>
            <input
              type="password"
              name="contrasena"
              value={formulario.contrasena}
              onChange={handleChange}
              className="w-full border border-gray-300 rounded-lg p-3 mt-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
              maxLength={100}
              required
            />
          </div>

          {/* Botón enviar */}
          <button
            type="submit"
            className="w-full bg-blue-600 text-white p-3 rounded-lg font-medium text-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {esCrearCuenta ? "Crear Cuenta" : "Iniciar Sesión"}
          </button>
        </form>

        {/* Botón para cambiar de modo */}
        <div className="mt-6 text-center">
          <button
            onClick={() => setEsCrearCuenta(!esCrearCuenta)}
            className="text-blue-600 text-lg font-medium hover:underline focus:outline-none"
          >
            {esCrearCuenta
              ? "¿Ya tienes cuenta? Iniciar sesión"
              : "¿No tienes cuenta? Crear cuenta"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AnadirUsuario;
